import { ref } from 'vue';

interface SomeTypes {
  name: string;
  class?: () => string;
  click: () => any;
  change: (v: string) => string;
}

const props = defineProps<{ title: string }>();

const emit = defineEmits<{
  (e: 'change'): void;
  (e: 'update', arg: { value: number }, d?: number): number;
}>();

defineSlots<{
  default?: () => any;
  header?: (props: { title: string }) => any;
  footer?: (props: { year: number }) => any;
  item?: (props: { id: number; name: string }) => any;
}>();

const count = ref(1);

// 应分析依赖，得到 props?.onUpdate
const handleUpdate = () => {
  // 应替换成 props?.onUpdate({ value: count.value++ })
  emit('update', { value: count.value });

  const update = 'update';
  emit(update, { value: count.value });
};
